/* 301 * 0x800000 = 2524971008, fits u32. Product needs s64. */
#define BS300_ENR_ETR_NUM_BASE  2524971008ULL

/* ENR NRR: coded = round(301 * 0x7FFFFF * nrr_x10 / (16000 * ma)) */
/* 301 * 0x7FFFFF = 2524970707 */
#define BS300_ENR_NRR_NUM_BASE  2524970707ULL

/* DDM2 mic delay: coded = round(mic_delay_raw * 8388607 / 1250) */
/* mic_delay_raw ∈ [0, 65535], product ≤ 549B, needs s64. */
#define BS300_DDM2_DELAY_NUM     8388607
#define BS300_DDM2_DELAY_DEN     1250

